using System.Collections;
using UnityEngine;
using UnityEngine.Events;

/// <summary>
/// Espinhos que invertem de lado (ex: baixo -> cima) a cada "intervalo"
/// segundos (add-on opcional — coloca-se na plataforma, junto com
/// MovingPlatform se quiseres que ela também se mova).
///
/// Coloca este script num GameObject FILHO da plataforma, com o sprite dos
/// espinhos + um Collider2D (Trigger) próprios — a rotação de 180° desse
/// filho leva o sprite e a zona de dano para o lado oposto juntos.
/// </summary>
[RequireComponent(typeof(Collider2D))]
[DisallowMultipleComponent]
public class InvertingSpikes : MonoBehaviour
{
    [Header("Temporização")]
    [Tooltip("Tempo (segundos) entre cada inversão.")]
    [Min(0.1f)] public float intervalo = 3f;

    [Tooltip("Duração (segundos) da rotação até ao lado oposto. 0 = instantâneo.")]
    [Min(0f)] public float duracaoRotacao = 0.25f;

    [Tooltip("Começa com os espinhos em baixo (true) ou em cima (false)?")]
    public bool comecaEmBaixo = true;

    [Header("Dano")]
    [Tooltip("Corações de dano ao tocar nos espinhos.")]
    [Min(0)] public int damage = 1;

    [Tooltip("Força de empurrão aplicada ao tocar nos espinhos.")]
    [Min(0f)] public float knockback = 6f;

    [Tooltip("Intervalo mínimo (segundos) entre danos de contacto, enquanto o player ficar em contacto.")]
    [Min(0.05f)] public float tickInterval = 0.6f;

    [Header("Eventos")]
    public UnityEvent onInverteu;

    private bool _emBaixo;
    private float _timer;
    private float _nextDamageTime;

    private void Awake()
    {
        _emBaixo = comecaEmBaixo;
        _timer = intervalo;

        // Garante orientação inicial coerente com "comecaEmBaixo" sem animação.
        transform.localRotation = _emBaixo ? Quaternion.identity : Quaternion.Euler(0f, 0f, 180f);
    }

    private void Update()
    {
        _timer -= Time.deltaTime;
        if (_timer > 0f) return;

        _timer = intervalo;
        _emBaixo = !_emBaixo;

        float targetZ = _emBaixo ? 0f : 180f;

        if (duracaoRotacao > 0f)
            StartCoroutine(RotateTo(targetZ));
        else
            transform.localRotation = Quaternion.Euler(0f, 0f, targetZ);

        onInverteu?.Invoke();
    }

    private IEnumerator RotateTo(float targetZ)
    {
        Quaternion from = transform.localRotation;
        Quaternion to = Quaternion.Euler(0f, 0f, targetZ);

        float t = 0f;
        while (t < duracaoRotacao)
        {
            t += Time.deltaTime;
            transform.localRotation = Quaternion.Slerp(from, to, Mathf.Clamp01(t / duracaoRotacao));
            yield return null;
        }

        transform.localRotation = to;
    }

    private void OnTriggerStay2D(Collider2D other) => TryHit(other);
    private void OnTriggerEnter2D(Collider2D other) => TryHit(other);

    private void TryHit(Collider2D other)
    {
        if (!other.CompareTag("Player")) return;
        if (Time.time < _nextDamageTime) return;
        if (damage <= 0) return;

        var info = new DamageInfo(damage, DamageType.Hazard, transform.position, knockback, null, ignoreDefense: true);

        if (PlayerCombat.TryDamagePlayer(other.transform, info))
            _nextDamageTime = Time.time + tickInterval;
    }

    private void OnDrawGizmosSelected()
    {
        Gizmos.color = Color.red;
        Vector3 dir = transform.up;
        Gizmos.DrawLine(transform.position, transform.position + dir * 0.5f);
    }
}
